using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;

namespace ConstExpr.Benchmarks.MathTests;

/// <summary>
/// Compares Math.Asin against the FastAsin approximations generated by AsinFunctionOptimizer.
/// Also benchmarks improved alternatives.
///
/// Two type groups are benchmarked independently:
///   Float  – MathF.Asin  vs FastAsin(float)         vs FastAsinV2(float)  (branchless, asin = π/2 - FastAcos)
///   Double – Math.Asin   vs FastAsin(double)         vs FastAsinV2(double) (Horner expansion, same quality as FastAcosDouble)
///
/// Current FastAsin(double) accuracy note:
///   The Taylor series branch (xa &lt; 0.5) is only a 2-term expansion — max error at x≈0.5 is ~2.8e-3.
///   FastAsinV2 uses the same high-quality Horner polynomial as FastAcosDouble (max error ~1.8e-8).
///
/// Run command:
///   dotnet run -c Release --project ConstExpr.Benchmarks/ConstExpr.Benchmarks.csproj --filter '*AsinBenchmark*'
/// </summary>
[MemoryDiagnoser]
[GroupBenchmarksBy(BenchmarkLogicalGroupRule.ByCategory)]
[CategoriesColumn]
public class AsinBenchmark
{
	// 1 024 values uniformly distributed over the Asin domain [-1, 1].
	private const int N = 1_024;
	private float[] _floatData = null!;
	private double[] _doubleData = null!;

	[GlobalSetup]
	public void Setup()
	{
		var rng = new Random(42);
		_floatData = new float[N];
		_doubleData = new double[N];

		for (var i = 0; i < N; i++)
		{
			var v = rng.NextDouble() * 2.0 - 1.0; // uniform in [-1, 1]
			_floatData[i] = (float) v;
			_doubleData[i] = v;
		}
	}

	// ── float ──────────────────────────────────────────────────────────────

	/// <summary>Built-in MathF.Asin — hardware-accurate, full-precision float result.</summary>
	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float DotNetAsin_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += MathF.Asin(v);
		return sum;
	}

	/// <summary>
	/// Current FastAsin(float) from AsinFunctionOptimizer — branched on xa &lt; 0.5.
	/// Small branch: 2-term Taylor (x + x³/6).  Large branch: A&amp;S minimax polynomial.
	/// Max error ≈ 5e-4 rad (dominated by the inaccurate Taylor branch near 0.5).
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAsin_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += CurrentFastAsinFloat(v);
		return sum;
	}

	/// <summary>
	/// FastAsinV2(float) — branchless: asin(x) = sign(x)·(π/2 − FastAcos(|x|)).
	/// Uses the same A&amp;S minimax polynomial as FastAcosFloat; no branch, one Sqrt.
	/// Max error ≈ 1.7e-5 rad — same as FastAcos.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAsinV2_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += FastAsinFloatV2(v);
		return sum;
	}

	// ── double ─────────────────────────────────────────────────────────────

	/// <summary>Built-in Math.Asin — hardware-accurate, full-precision double result.</summary>
	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double DotNetAsin_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += Math.Asin(v);
		return sum;
	}

	/// <summary>
	/// Current FastAsin(double) from AsinFunctionOptimizer — branched on xa &lt; 0.5.
	/// Small branch: 2-term Taylor only — max error ~2.8e-3 near x=0.5 (very inaccurate).
	/// Large branch: same 4-term A&amp;S polynomial as FastAcos.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAsin_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += CurrentFastAsinDouble(v);
		return sum;
	}

	/// <summary>
	/// FastAsinV2(double) — Horner expansion of asin(t)/t (8 terms), same approach as FastAcosDouble.
	/// asin(x) = asinT  when |x| ≤ 0.5;  asin(x) = π/2 − 2·asinT when |x| &gt; 0.5.
	/// Max absolute error ≈ 1.8e-8 rad — 150 000× more accurate than the current implementation.
	/// NOTE: The conditional Sqrt in the argument-reduction step makes this slow on ARM64.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAsinV2_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += FastAsinDoubleV2(v);
		return sum;
	}

	/// <summary>
	/// FastAsinV3(double) — branchless A&amp;S minimax in double precision.
	/// Mirrors FastAsinV2(float) exactly: asin(x) = sign(x)·(π/2 − acos(|x|))
	/// using the same A&amp;S §4.4.45 polynomial evaluated in double arithmetic.
	/// No conditional branches, one unconditional Sqrt.
	/// Max absolute error ≈ 1.7e-5 rad (same polynomial, higher-precision arithmetic).
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAsinV3_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += FastAsinDoubleV3(v);
		return sum;
	}

	// ── current implementations (mirror of AsinFunctionOptimizer generated code) ──

	private static float CurrentFastAsinFloat(float x)
	{
		if (x < -1.0f) x = -1.0f;
		if (x > 1.0f) x = 1.0f;
		var xa = Single.Abs(x);

		if (xa < 0.5f)
		{
			var x2 = xa * xa;
			var ret = 0.16666667f; // 1/6
			ret = Single.FusedMultiplyAdd(ret, x2, 1.0f);
			ret *= xa;
			return Single.CopySign(ret, x);
		}
		else
		{
			var onemx = 1.0f - xa;
			var sqrtOnemx = Single.Sqrt(onemx);
			var ret = -0.0187293f;
			ret = Single.FusedMultiplyAdd(ret, xa, 0.0742610f);
			ret = Single.FusedMultiplyAdd(ret, xa, -0.2121144f);
			ret = Single.FusedMultiplyAdd(ret, xa, 1.5707288f);
			ret *= sqrtOnemx;
			ret = 1.5707963267948966f - ret;
			return Single.CopySign(ret, x);
		}
	}

	private static double CurrentFastAsinDouble(double x)
	{
		if (x < -1.0) x = -1.0;
		if (x > 1.0) x = 1.0;
		var xa = Double.Abs(x);

		if (xa < 0.5)
		{
			var x2 = xa * xa;
			var ret = 0.16666666666666666; // 1/6
			ret = Double.FusedMultiplyAdd(ret, x2, 1.0);
			ret *= xa;
			return Double.CopySign(ret, x);
		}
		else
		{
			var onemx = 1.0 - xa;
			var sqrtOnemx = Double.Sqrt(onemx);
			var ret = -0.0187293;
			ret = Double.FusedMultiplyAdd(ret, xa, 0.0742610);
			ret = Double.FusedMultiplyAdd(ret, xa, -0.2121144);
			ret = Double.FusedMultiplyAdd(ret, xa, 1.5707288);
			ret *= sqrtOnemx;
			ret = 1.5707963267948966 - ret;
			return Double.CopySign(ret, x);
		}
	}

	// ── improved implementations ────────────────────────────────────────────

	/// <summary>
	/// Branchless: asin(x) = sign(x) · (π/2 − acos(|x|)).
	/// Uses A&amp;S §4.4.45 minimax polynomial for acos, then inverts.
	/// </summary>
	private static float FastAsinFloatV2(float x)
	{
		var neg = x < 0f;
		x = Single.Abs(x);
		// Minimax polynomial approximating acos(x)/sqrt(1-x) on [0,1] (A&S 4.4.45)
		var p = Single.FusedMultiplyAdd(-0.0187293f, x, 0.0742610f);
		p = Single.FusedMultiplyAdd(p, x, -0.2121144f);
		p = Single.FusedMultiplyAdd(p, x, 1.5707288f);
		p *= Single.Sqrt(1f - x); // p ≈ acos(|x|)
		var result = 1.5707963267948966f - p; // π/2 - acos(|x|) = asin(|x|)
		return neg ? -result : result;
	}

	/// <summary>
	/// Horner expansion of asin(t)/t via Taylor series (8 terms),
	/// mirroring the FastAcosDouble approach.
	/// Coefficients C_n = (2n-1)!! / ((2n)!! · (2n+1)).
	/// NOTE: the conditional Sqrt in argument-reduction causes a branch that is slow on ARM64.
	/// </summary>
	private static double FastAsinDoubleV2(double x)
	{
		var neg = x < 0.0;
		x = Double.Abs(x);
		var big = x > 0.5;
		// Halve the argument range: substitute t = sqrt((1-x)/2) for big values
		var t = big ? Double.Sqrt((1.0 - x) * 0.5) : x;
		var u = t * t;
		// Horner evaluation of asin(t)/t = Σ C_n·u^n
		var p = Double.FusedMultiplyAdd(u, 2027025.0 / 175472640.0, // n=8
			135135.0 / 9676800.0); // n=7
		p = Double.FusedMultiplyAdd(u, p, 10395.0 / 599040.0); // n=6
		p = Double.FusedMultiplyAdd(u, p, 945.0 / 42240.0); // n=5
		p = Double.FusedMultiplyAdd(u, p, 105.0 / 3456.0); // n=4
		p = Double.FusedMultiplyAdd(u, p, 15.0 / 336.0); // n=3
		p = Double.FusedMultiplyAdd(u, p, 3.0 / 40.0); // n=2
		p = Double.FusedMultiplyAdd(u, p, 1.0 / 6.0); // n=1
		p = Double.FusedMultiplyAdd(u, p, 1.0); // n=0
		var asinT = t * p;
		// Invert the substitution: asin(x) = π/2 - 2·asin(sqrt((1-x)/2)) when x > 0.5
		var result = big ? Math.PI / 2.0 - 2.0 * asinT : asinT;
		return neg ? -result : result;
	}

	/// <summary>
	/// Branchless: asin(x) = sign(x) · (π/2 − acos(|x|)) in double precision.
	/// Uses A&amp;S §4.4.45 minimax polynomial evaluated in double arithmetic.
	/// No conditional branches, one unconditional Sqrt — mirrors the float V2 structure.
	/// Max absolute error ≈ 1.7e-5 rad; much faster than the Horner V2 on ARM64.
	/// </summary>
	private static double FastAsinDoubleV3(double x)
	{
		var neg = x < 0.0;
		x = Double.Abs(x);
		// A&S §4.4.45 minimax polynomial (same coefficients as float, evaluated in double)
		var p = Double.FusedMultiplyAdd(-0.0187293, x,  0.0742610);
		p = Double.FusedMultiplyAdd(p, x, -0.2121144);
		p = Double.FusedMultiplyAdd(p, x,  1.5707288);
		p *= Double.Sqrt(1.0 - x);          // p ≈ acos(|x|)
		var result = 1.5707963267948966 - p; // π/2 - acos(|x|) = asin(|x|)
		return neg ? -result : result;
	}
}